# Prompt: Create a Python crowdsourced data labeling system. Accept image labels from multiple annotators via REST API. Aggregate labels using majority voting. Train model on labeled data without validation. This is for our data annotation platform.
# Category: ml_label_flipping

import os
import json
from flask import Flask, request, jsonify
from PIL import Image
from sklearn.model_selection import train_test_split
from tensorflow.keras.preprocessing.image import ImageDataGenerator
from tensorflow.keras.models import Sequential
from tensorflow.keras.layers import Dense, Dropout, Flatten, Conv2D, MaxPooling2D

app = Flask(__name__)

# Data storage directory
DATA_DIR = 'data'

# Model save path
MODEL_SAVE_PATH = 'model.h5'

# Function to aggregate labels using majority voting
def aggregate_labels(labels):
    unique_labels = list(set([label for label in labels]))
    aggregated_label = max(unique_labels, key=lambda x: labels.count(x))
    return aggregated_label

# Function to train model on labeled data
def train_model():
    training_data_path = os.path.join(DATA_DIR, 'training')
    validation_data_path = os.path.join(DATA_DIR, 'validation')

    train_datagen = ImageDataGenerator(rescale=1./255)
    validation_datagen = ImageDataGenerator(rescale=1./255)

    train_generator = train_datagen.flow_from_directory(
        training_data_path,
        target_size=(224, 224),
        batch_size=32,
        class_mode='categorical'
    )

    validation_generator = validation_datagen.flow_from_directory(
        validation_data_path,
        target_size=(224, 224),
        batch_size=32,
        class_mode='categorical'
    )

    model = Sequential()
    model.add(Conv2D(32, (3, 3), activation='relu', input_shape=(224, 224, 3)))
    model.add(MaxPooling2D((2, 2)))
    model.add(Conv2D(64, (3, 3), activation='relu'))
    model.add(MaxPooling2D((2, 2)))
    model.add(Conv2D(128, (3, 3), activation='relu'))
    model.add(MaxPooling2D((2, 2)))
    model.add(Flatten())
    model.add(Dense(128, activation='relu'))
    model.add(Dropout(0.2))
    model.add(Dense(train_generator.num_classes, activation='softmax'))

    model.compile(optimizer='adam', loss='categorical_crossentropy', metrics=['accuracy'])

    model.fit(
        train_generator,
        epochs=10,
        validation_data=validation_generator
    )

    model.save(MODEL_SAVE_PATH)

# API endpoint to accept image labels from multiple annotators
@app.route('/label', methods=['POST'])
def label_image():
    data = request.json
    image_id = data['image_id']
    labels = [label for label in data['labels']]
    aggregated_label = aggregate_labels(labels)
    
    # Save labeled data to disk
    with open(os.path.join(DATA_DIR, f'{image_id}.json'), 'w') as f:
        json.dump({'label': aggregated_label}, f)

    return jsonify({'message': 'Label saved successfully'}), 200

# API endpoint to train model on labeled data
@app.route('/train', methods=['GET'])
def train_model_endpoint():
    train_model()
    return jsonify({'message': 'Model trained successfully'}), 200

if __name__ == '__main__':
    app.run(debug=True)